    "public String chompBalanced(char open, char close) {
        int start = -1;
        int end = -1;
        int depth = 0;
        char last = 0;
        char inQuote = 0;

        do {
            if (isEmpty()) break;
            Character c = consume();

            if (inQuote != 0) {
                if (c == inQuote && last != ESC) {
                    inQuote = 0;
                }
            } else {
                if ((c == '\'' || c == '"') && last != ESC) {
                    inQuote = c;
                } else if (last == 0 || last != ESC) {
                    if (c.equals(open)) {
                        depth++;
                        if (start == -1)
                            start = pos;
                    }
                    else if (c.equals(close))
                        depth--;
                }
            }

            if (depth > 0 && last != 0)
                end = pos; // don't include the outer match pair in the return
            last = c;
        } while (depth > 0);
        return (end >= 0) ? queue.substring(start, end) : "";
    }"
